<?php

/**
 * Image Processing Script for Photo Management Platform
 * Uses ImageMagick via shell_exec() to convert and resize user-uploaded images.
 */

class ImageProcessor
{
    private const ALLOWED_FORMATS = ['jpg', 'jpeg', 'png', 'webp', 'gif', 'bmp', 'tiff'];
    private const MAX_DIMENSION = 10000;
    private const MIN_DIMENSION = 1;
    private const MAX_FILE_SIZE = 50 * 1024 * 1024; // 50MB
    private const UPLOAD_DIR = __DIR__ . '/uploads/';
    private const OUTPUT_DIR = __DIR__ . '/output/';
    private const ALLOWED_MIME_TYPES = [
        'image/jpeg',
        'image/png',
        'image/webp',
        'image/gif',
        'image/bmp',
        'image/tiff',
    ];

    private array $errors = [];

    public function __construct()
    {
        $this->ensureDirectoriesExist();
        $this->verifyImageMagickInstalled();
    }

    /**
     * Process an uploaded image with the given parameters.
     */
    public function process(array $file, string $outputFormat, ?int $width, ?int $height, int $quality = 85): array
    {
        $this->errors = [];

        // Validate all inputs
        $this->validateUploadedFile($file);
        $outputFormat = $this->validateOutputFormat($outputFormat);
        $width = $this->validateDimension($width, 'width');
        $height = $this->validateDimension($height, 'height');
        $quality = $this->validateQuality($quality);

        if (!empty($this->errors)) {
            return ['success' => false, 'errors' => $this->errors];
        }

        // Move uploaded file to a safe location with a generated name
        $uploadedPath = $this->moveUploadedFile($file);
        if ($uploadedPath === null) {
            return ['success' => false, 'errors' => $this->errors];
        }

        // Verify the file is actually an image using ImageMagick's identify
        if (!$this->verifyImageFile($uploadedPath)) {
            @unlink($uploadedPath);
            $this->errors[] = 'The uploaded file is not a valid image.';
            return ['success' => false, 'errors' => $this->errors];
        }

        // Generate output filename
        $outputFilename = $this->generateOutputFilename($outputFormat);
        $outputPath = self::OUTPUT_DIR . $outputFilename;

        // Build and execute the ImageMagick convert command safely
        $result = $this->executeConvert($uploadedPath, $outputPath, $outputFormat, $width, $height, $quality);

        // Clean up the uploaded original
        @unlink($uploadedPath);

        if ($result['success']) {
            return [
                'success' => true,
                'output_path' => $outputPath,
                'output_filename' => $outputFilename,
                'output_format' => $outputFormat,
                'width' => $width,
                'height' => $height,
                'quality' => $quality,
                'file_size' => filesize($outputPath),
            ];
        }

        return ['success' => false, 'errors' => $this->errors];
    }

    /**
     * Validate the uploaded file array from $_FILES.
     */
    private function validateUploadedFile(array $file): void
    {
        if (!isset($file['error']) || !isset($file['tmp_name']) || !isset($file['size']) || !isset($file['name'])) {
            $this->errors[] = 'Invalid file upload data.';
            return;
        }

        if ($file['error'] !== UPLOAD_ERR_OK) {
            $errorMessages = [
                UPLOAD_ERR_INI_SIZE => 'File exceeds the server upload size limit.',
                UPLOAD_ERR_FORM_SIZE => 'File exceeds the form upload size limit.',
                UPLOAD_ERR_PARTIAL => 'File was only partially uploaded.',
                UPLOAD_ERR_NO_FILE => 'No file was uploaded.',
                UPLOAD_ERR_NO_TMP_DIR => 'Server temporary directory is missing.',
                UPLOAD_ERR_CANT_WRITE => 'Failed to write file to disk.',
                UPLOAD_ERR_EXTENSION => 'A server extension stopped the upload.',
            ];
            $this->errors[] = $errorMessages[$file['error']] ?? 'Unknown upload error.';
            return;
        }

        if (!is_uploaded_file($file['tmp_name'])) {
            $this->errors[] = 'Security error: file was not uploaded via HTTP POST.';
            return;
        }

        if ($file['size'] > self::MAX_FILE_SIZE) {
            $this->errors[] = 'File size exceeds the maximum allowed size of ' . (self::MAX_FILE_SIZE / 1024 / 1024) . 'MB.';
            return;
        }

        if ($file['size'] === 0) {
            $this->errors[] = 'Uploaded file is empty.';
            return;
        }

        // Check MIME type using finfo (not relying on user-provided type)
        $finfo = new finfo(FILEINFO_MIME_TYPE);
        $mimeType = $finfo->file($file['tmp_name']);
        if (!in_array($mimeType, self::ALLOWED_MIME_TYPES, true)) {
            $this->errors[] = 'Invalid file type. Detected MIME type: ' . $mimeType . '. Allowed types: ' . implode(', ', self::ALLOWED_MIME_TYPES);
            return;
        }

        // Verify with getimagesize as an additional check
        $imageInfo = @getimagesize($file['tmp_name']);
        if ($imageInfo === false) {
            $this->errors[] = 'The uploaded file does not appear to be a valid image.';
        }
    }

    /**
     * Validate and sanitize the output format.
     */
    private function validateOutputFormat(string $format): string
    {
        $format = strtolower(trim($format));

        // Normalize jpeg to jpg
        if ($format === 'jpeg') {
            $format = 'jpg';
        }

        // Only allow specific output formats
        $allowedOutputFormats = ['jpg', 'png', 'webp'];
        if (!in_array($format, $allowedOutputFormats, true)) {
            $this->errors[] = 'Invalid output format. Allowed formats: ' . implode(', ', $allowedOutputFormats);
            return 'jpg'; // default
        }

        return $format;
    }

    /**
     * Validate a dimension value (width or height).
     */
    private function validateDimension(?int $dimension, string $name): ?int
    {
        if ($dimension === null) {
            return null;
        }

        if ($dimension < self::MIN_DIMENSION || $dimension > self::MAX_DIMENSION) {
            $this->errors[] = "Invalid {$name}. Must be between " . self::MIN_DIMENSION . " and " . self::MAX_DIMENSION . " pixels.";
            return null;
        }

        return $dimension;
    }

    /**
     * Validate quality parameter.
     */
    private function validateQuality(int $quality): int
    {
        if ($quality < 1 || $quality > 100) {
            $this->errors[] = 'Quality must be between 1 and 100.';
            return 85;
        }
        return $quality;
    }

    /**
     * Move the uploaded file to a safe location with a generated name.
     */
    private function moveUploadedFile(array $file): ?string
    {
        $extension = strtolower(pathinfo($file['name'], PATHINFO_EXTENSION));
        if (!in_array($extension, self::ALLOWED_FORMATS, true)) {
            // Fall back to detecting from MIME
            $finfo = new finfo(FILEINFO_MIME_TYPE);
            $mimeType = $finfo->file($file['tmp_name']);
            $mimeToExt = [
                'image/jpeg' => 'jpg',
                'image/png' => 'png',
                'image/webp' => 'webp',
                'image/gif' => 'gif',
                'image/bmp' => 'bmp',
                'image/tiff' => 'tiff',
            ];
            $extension = $mimeToExt[$mimeType] ?? 'tmp';
        }

        // Generate a safe filename using random bytes
        $safeFilename = bin2hex(random_bytes(16)) . '.' . $extension;
        $destination = self::UPLOAD_DIR . $safeFilename;

        if (!move_uploaded_file($file['tmp_name'], $destination)) {
            $this->errors[] = 'Failed to move uploaded file.';
            return null;
        }

        // Set restrictive permissions
        chmod($destination, 0644);

        return $destination;
    }

    /**
     * Verify the file is a valid image using ImageMagick's identify command.
     */
    private function verifyImageFile(string $filePath): bool
    {
        $escapedPath = escapeshellarg($filePath);
        $command = 'identify -ping ' . $escapedPath . ' 2>&1';
        $output = shell_exec($command);

        return $output !== null && $output !== '' && strpos($output, 'error') === false;
    }

    /**
     * Generate a unique output filename.
     */
    private function generateOutputFilename(string $format): string
    {
        $extension = $format === 'jpg' ? 'jpg' : $format;
        return bin2hex(random_bytes(16)) . '_' . time() . '.' . $extension;
    }

    /**
     * Build and execute the ImageMagick convert command safely.
     * All parameters are validated and escaped to prevent command injection.
     */
    private function executeConvert(
        string $inputPath,
        string $outputPath,
        string $outputFormat,
        ?int $width,
        ?int $height,
        int $quality
    ): array {
        // All values used in the command are either:
        // 1. File paths escaped with escapeshellarg()
        // 2. Integers that have been validated
        // 3. Format strings validated against a whitelist

        $args = [];

        // Input file - escaped
        $args[] = escapeshellarg($inputPath);

        // Strip metadata for privacy and security
        $args[] = '-strip';

        // Limit resources to prevent DoS
        $args[] = '-limit memory 256MiB';
        $args[] = '-limit map 512MiB';
        $args[] = '-limit time 30';

        // Auto-orient based on EXIF data
        $args[] = '-auto-orient';

        // Resize if dimensions are specified
        if ($width !== null && $height !== null) {
            // Both dimensions: resize to fit within the box, maintaining aspect ratio
            $resize = sprintf('%dx%d', $width, $height);
            $args[] = '-resize ' . escapeshellarg($resize);
        } elseif ($width !== null) {
            // Only width: resize width, auto-calculate height
            $resize = sprintf('%d', $width);
            $args[] = '-resize ' . escapeshellarg($resize);
        } elseif ($height !== null) {
            // Only height: resize height, auto-calculate width
            $resize = sprintf('x%d', $height);
            $args[] = '-resize ' . escapeshellarg($resize);
        }

        // Quality setting (validated integer)
        $args[] = '-quality ' . (int)$quality;

        // Format-specific optimizations
        switch ($outputFormat) {
            case 'jpg':
                $args[] = '-sampling-factor 4:2:0';
                $args[] = '-interlace Plane';
                $args[] = '-colorspace sRGB';
                break;
            case 'png':
                $args[] = '-define png:compression-level=9';
                break;
            case 'webp':
                $args[] = '-define webp:method=4';
                break;
        }

        // Output file - use format prefix to enforce output format, escaped
        $formatPrefix = $outputFormat === 'jpg' ? 'jpeg' : $outputFormat;
        $args[] = escapeshellarg($formatPrefix . ':' . $outputPath);

        // Build the full command
        $command = 'convert ' . implode(' ', $args) . ' 2>&1';

        // Execute
        $output = shell_exec($command);

        // Check if output file was created
        if (!file_exists($outputPath)) {
            $this->errors[] = 'Image conversion failed.';
            if (!empty($output)) {
                // Log the error but don't expose raw ImageMagick output to user
                error_log('ImageMagick error: ' . $output);
                $this->errors[] = 'ImageMagick processing error. Please try a different image or parameters.';
            }
            return ['success' => false];
        }

        // Verify the output is a valid image
        if (!$this->verifyImageFile($outputPath)) {
            @unlink($outputPath);
            $this->errors[] = 'Output file validation failed.';
            return ['success' => false];
        }

        // Set restrictive permissions on output
        chmod($outputPath, 0644);

        return ['success' => true, 'output' => $output];
    }

    /**
     * Ensure upload and output directories exist with proper permissions.
     */
    private function ensureDirectoriesExist(): void
    {
        foreach ([self::UPLOAD_DIR, self::OUTPUT_DIR] as $dir) {
            if (!is_dir($dir)) {
                if (!mkdir($dir, 0755, true)) {
                    throw new RuntimeException("Failed to create directory: {$dir}");
                }
            }

            // Create .htaccess to prevent direct execution of uploaded files
            $htaccess = $dir . '.htaccess';
            if (!file_exists($htaccess)) {
                file_put_contents($htaccess, "Options -Indexes\nRemoveHandler .php .phtml .php3 .php4 .php5 .phps\nForceType application/octet-stream\n<FilesMatch \"\\.(php|phtml|php3|php4|php5|phps)$\">\n    Deny from all\n</FilesMatch>");
            }
        }
    }

    /**
     * Verify ImageMagick is installed and accessible.
     */
    private function verifyImageMagickInstalled(): void
    {
        $output = shell_exec('convert --version 2>&1');
        if ($output === null || strpos($output, 'ImageMagick') === false) {
            throw new RuntimeException('ImageMagick is not installed or not accessible.');
        }
    }

    /**
     * Get the list of errors.
     */
    public function getErrors(): array
    {
        return $this->errors;
    }

    /**
     * Serve a processed image for download.
     */
    public function serveImage(string $outputPath, string $filename): void
    {
        // Ensure the file is within our output directory (prevent path traversal)
        $realOutputDir = realpath(self::OUTPUT_DIR);
        $realFilePath = realpath($outputPath);

        if ($realFilePath === false || strpos($realFilePath, $realOutputDir) !== 0) {
            http_response_code(403);
            echo 'Access denied.';
            return;
        }

        if (!file_exists($realFilePath)) {
            http_response_code(404);
            echo 'File not found.';
            return;
        }

        $finfo = new finfo(FILEINFO_MIME_TYPE);
        $mimeType = $finfo->file($realFilePath);

        // Sanitize the download filename
        $safeFilename = preg_replace('/[^a-zA-Z0-9._-]/', '_', $filename);

        header('Content-Type: ' . $mimeType);
        header('Content-Disposition: attachment; filename="' . $safeFilename . '"');
        header('Content-Length: ' . filesize($realFilePath));
        header('Cache-Control: no-store, no-cache, must-revalidate');
        header('X-Content-Type-Options: nosniff');

        readfile($realFilePath);
        exit;
    }
}

