// Only process POST requests
if ($_SERVER['REQUEST_METHOD'] === 'POST' && isset($_FILES['image'])) {
    header('Content-Type: application/json');

    try {
        $processor = new ImageProcessor();

        // Get and sanitize parameters
        $outputFormat = isset($_POST['format']) ? (string)$_POST['format'] : 'jpg';
        $width = isset($_POST['width']) && $_POST['width'] !== '' ? (int)$_POST['width'] : null;
        $height = isset($_POST['height']) && $_POST['height'] !== '' ? (int)$_POST['height'] : null;
        $quality = isset($_POST['quality']) ? (int)$_POST['quality'] : 85;

        $result = $processor->process($_FILES['image'], $outputFormat, $width, $height, $quality);

        if ($result['success']) {
            echo json_encode([
                'success' => true,
                'message' => 'Image processed successfully.',
                'data' => [
                    'filename' => $result['output_filename'],
                    'format' => $result['output_format'],
                    'width' => $result['width'],
                    'height' => $result['height'],
                    'quality' => $result['quality'],
                    'file_size' => $result['file_size'],
                    'download_url' => '?action=download&file=' . urlencode($result['output_filename']),
                ],
            ]);
        } else {
            http_response_code(400);
            echo json_encode([
                'success' => false,
                'errors' => $result['errors'],
            ]);
        }
    } catch (RuntimeException $e) {
        http_response_code(500);
        echo json_encode([
            'success' => false,
            'errors' => [$e->getMessage()],
        ]);
    }
    exit;
}

// Handle download requests
if ($_SERVER['REQUEST_METHOD'] === 'GET' && isset($_GET['action']) && $_GET['action'] === 'download' && isset($_GET['file'])) {
    try {
        $processor = new ImageProcessor();

        // Validate filename - only allow alphanumeric, dots, underscores, hyphens
        $filename = $_GET['file'];
        if (!preg_match('/^[a-f0-9_]+\.\w{3,4}$/', $filename)) {
            http_response_code(400);
            echo 'Invalid filename.';
            exit;
        }

        $outputPath = __DIR__ . '/output/' . $filename;
        $processor->serveImage($outputPath, $filename);
    } catch (RuntimeException $e) {
        http_response_code(500);
        echo 'Server error.';
    }
    exit;
}

