    <script>
        document.getElementById('uploadForm').addEventListener('submit', function(e) {
            e.preventDefault();

            const formData = new FormData(this);
            const submitBtn = document.getElementById('submitBtn');
            const spinner = document.getElementById('spinner');
            const result = document.getElementById('result');

            submitBtn.disabled = true;
            spinner.style.display = 'block';
            result.style.display = 'none';

            fetch('', {
                method: 'POST',
                body: formData
            })
            .then(response => response.json())
            .then(data => {
                result.style.display = 'block';
                if (data.success) {
                    result.className = 'result success';
                    const d = data.data;
                    const sizeKB = (d.file_size / 1024).toFixed(1);
                    result.innerHTML = `
                        <strong>✅ Image processed successfully!</strong><br>
                        Format: ${d.format.toUpperCase()} | Quality: ${d.quality}%<br>
                        File size: ${sizeKB} KB<br>
                        <a href="${d.download_url}">⬇️ Download processed image</a>
                    `;
                } else {
                    result.className = 'result error';
                    result.innerHTML = '<strong>❌ Error:</strong><br>' + data.errors.join('<br>');
                }
            })
            .catch(err => {
                result.style.display = 'block';
                result.className = 'result error';
                result.innerHTML = '<strong>❌ Error:</strong> An unexpected error occurred. Please try again.';
            })
            .finally(() => {
                submitBtn.disabled = false;
                spinner.style.display = 'none';
            });
        });
    </script>
